def seed_all():
    conn = get_mysql()
    cursor = conn.cursor()

    # Only clear rows with no quiz history attached (avoids FK errors on old test data)
    cursor.execute("""
        DELETE FROM topik_questions
        WHERE exam_no = %s
          AND id NOT IN (SELECT DISTINCT question_id FROM quiz_results)
    """, (EXAM_NO,))
    cursor.execute("DELETE FROM topik_writing_questions WHERE exam_no = %s", (EXAM_NO,))
    conn.commit()
    print(f"🗑️  Cleared existing exam_no={EXAM_NO} rows (kept any with quiz history)")

    saved = 0
    for qno, text, opts, ans in LISTENING:
        cursor.execute("""
            INSERT INTO topik_questions
                (exam_no, section, question_no, question, option_1, option_2, option_3, option_4, audio_url, answer)
            VALUES (%s, 'listening', %s, %s, %s, %s, %s, %s, %s, %s)
        """, (EXAM_NO, qno, text, opts[0], opts[1], opts[2], opts[3], AUDIO_URL, ans))
        saved += 1
    print(f"💾 Saved {len(LISTENING)} listening questions")

    for qno, text, opts, ans in READING:
        cursor.execute("""
            INSERT INTO topik_questions
                (exam_no, section, question_no, question, option_1, option_2, option_3, option_4, audio_url, answer)
            VALUES (%s, 'reading', %s, %s, %s, %s, %s, %s, NULL, %s)
        """, (EXAM_NO, qno, text, opts[0], opts[1], opts[2], opts[3], ans))
        saved += 1
    print(f"💾 Saved {len(READING)} reading questions")

    for qno, prompt, blanks, min_c, max_c, model_answer, points in WRITING:
        cursor.execute("""
            INSERT INTO topik_writing_questions
                (exam_no, question_no, prompt, blank_count, min_chars, max_chars, model_answer, points)
            VALUES (%s, %s, %s, %s, %s, %s, %s, %s)
        """, (EXAM_NO, qno, prompt, blanks, min_c, max_c, model_answer, points))
        saved += 1
    print(f"💾 Saved {len(WRITING)} writing questions")

    conn.commit()
    cursor.close()
    conn.close()
    print(f"\n🎉 Done! Total {saved} rows seeded for exam_no={EXAM_NO}")
    print(f"   Listening: {len(LISTENING)} | Reading: {len(READING)} | Writing: {len(WRITING)}")


if __name__ == "__main__":
    seed_all()
